$$
A_{vs} = \frac{\dot{V}_o}{\dot{V}_s} = \frac{\dot{V}_{b'e}}{\dot{V}_s} \cdot \frac{\dot{V}_o}{\dot{V}_{b'e}}
= \frac{r_{b'e}}{R_s + r_{be} + \dfrac{1}{j\omega C_1}} \cdot g_m \cdot \frac{-R_C R_L}{R_C + R_L + \dfrac{1}{j\omega C_2}}
= \frac{-\beta_0 R_C R_L}{(R_s + r_{be})(R_C R_L)} \cdot \frac{1}{\left(1 + \dfrac{\omega_{c1}}{j\omega}\right)\left(1 + \dfrac{\omega_{c2}}{j\omega}\right)}
$$
由此可得 $A_{v0} = \dfrac{-\beta_0 R_C / R_L}{R_s + r_{be}} = \dfrac{-100 \times \dfrac{1 \times 5}{1 + 5}}{0.5 + 1.833} = -35.7$
$$
f_{L1} = \frac{1}{2\pi} \cdot \frac{1}{(R_s + r_{be})C_1} = \frac{1}{2\pi} \times \left[(0.5 + 1.833) \times 10^3 \times 1 \times 10^{-6}\right]^{-1} \, \mathrm{Hz} = 68.22 \, \mathrm{Hz}
$$
$$
f_{L2} = \frac{1}{2\pi} \cdot \frac{1}{(R_C + R_L)C_2} = \frac{1}{2\pi} \times \left[6 \times 10^3 \times 1.5 \times 10^{-6}\right]^{-1} \, \mathrm{Hz} = 17.68 \, \mathrm{Hz}
$$

